    protected virtual async Task<IQueryable<PlaceWithNavigationProperties>> GetQueryForNavigationPropertiesAsync()
    {
        return from place in (await GetDbSetAsync())
               join placeCategory in (await GetDbContextAsync()).Set<PlaceCategory>() on place.PlaceCategoryId equals placeCategory.Id into placeCategories
               from placeCategory in placeCategories.DefaultIfEmpty()
               join province in (await GetDbContextAsync()).Set<Province>() on place.ProvinceId equals province.Id into provinces
               from province in provinces.DefaultIfEmpty()
               join ward in (await GetDbContextAsync()).Set<Ward>() on place.WardId equals ward.Id into wards
               from ward in wards.DefaultIfEmpty()
               select new PlaceWithNavigationProperties
               {
                   Place = place,
                   PlaceCategory = placeCategory,
                   Province = province,
                   Ward = ward
               };
    }

